<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Security Audit</title><style>body{margin:0;background:#f5f7fb;color:#1f2a37;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Arial,sans-serif}header{background:#153764;color:white;padding:18px 24px}.wrap{max-width:1240px;margin:0 auto;padding:22px 16px}.card{background:white;border:1px solid #d9dee8;border-radius:8px;padding:18px}.bar{display:grid;grid-template-columns:repeat(7,1fr) auto;gap:10px;margin-bottom:14px}input,select{min-height:40px;border:1.5px solid #cbd3df;border-radius:6px;padding:8px 10px}.btn{border:0;border-radius:6px;padding:10px 14px;font-weight:900;text-decoration:none;display:inline-flex;background:#153764;color:white}.btn.light{background:white;color:#153764;border:1.5px solid #d9dee8}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:9px 8px;border-bottom:1px solid #edf0f5;font-size:13px;vertical-align:top}.status{padding:3px 8px;border-radius:999px;background:#eef3f9;color:#153764;font-weight:900;font-size:11px}@media(max-width:1000px){.bar{grid-template-columns:1fr 1fr}table{display:block;overflow-x:auto}}</style></head><body><header><h1>Security Audit Log</h1></header><main class="wrap"><div class="card"><form class="bar" method="GET"><input name="module" value="{{ request('module') }}" placeholder="Module"><input name="event_type" value="{{ request('event_type') }}" placeholder="Event"><input name="user_id" value="{{ request('user_id') }}" placeholder="User ID"><input name="ip_address" value="{{ request('ip_address') }}" placeholder="IP"><select name="status"><option value="">Status</option><option value="success">success</option><option value="failed">failed</option></select><input type="date" name="date_from" value="{{ request('date_from') }}"><input type="date" name="date_to" value="{{ request('date_to') }}"><button class="btn" type="submit">Filter</button></form><table><thead><tr><th>Date</th><th>User</th><th>Module</th><th>Event</th><th>Action</th><th>IP</th><th>Status</th><th></th></tr></thead><tbody>@foreach($logs as $log)<tr><td>{{ optional($log->created_at)->format('Y-m-d H:i:s') }}</td><td>{{ $log->user_id ?: 'guest' }}</td><td>{{ $log->module }}</td><td>{{ $log->event_type }}</td><td>{{ $log->action }}</td><td>{{ $log->ip_address }}</td><td><span class="status">{{ $log->status }}</span></td><td><a class="btn light" href="{{ route('admin.security.audit.show',$log) }}">Detail</a></td></tr>@endforeach</tbody></table>{{ $logs->links() }}</div></main></body></html>
